elements.onDown:
function(event, data, view, point, width, height) {
data.a('logo.color1', '#FFC826');
data.a('logo.color2', '#F24D63');
data.a('logo.color3','#48F4E8');
data.a('logo.color4','rgb(105,196,245)');
data.a('logo.text.color', '#45C4F9');
data.a('logo.text.color', 'white');
ht.Default.startAnim({
    duration: 200,
    easing: function (t) {
        return 1 - (--t) * t * t * t;
    },
    action: function(v, t){ 
        data.a('logo.clip', 0.4 + 0.6 * v);
    }
});
}

elements.onUp:
function(event, data, view, point, width, height) {
data.a('logo.color1', undefined);
data.a('logo.color2', undefined);
data.a('logo.color3', undefined);
data.a('logo.color4', undefined);
data.a('logo.text.color', undefined);
ht.Default.startAnim({
    duration: 200,
    easing: function (t) {
        return 1 - (--t) * t * t * t;
    },
    action: function(v, t){ 
        data.a('logo.clip', 1 - 0.6 * v);
    }
});
}

